var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"평소 듣던 사이렌이랑 달라.","JPN":"いつもと音が違う。","ENG":"No, it's a different alarm from what I'm used to.","TWN":"和平時聽到的警報聲不一樣。"},"stage":{"bg":"DORMITORY_3","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L4_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"이건 분명 최고 단계 경보일 텐데…?!","JPN":"これは確か、最高段階の警報のはず……！","ENG":"I think this is the highest alert...!","TWN":"這應該是最高等級的警報……？！"},"stage":{"bg":"DORMITORY_3","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L6_1","type":"dialog","speaker":"BROADCAST_HAVEN_NULL_NULL","text":{"KOREA":"<color=#ffd34c>3종 침식체, 통칭 키키모라가 출몰했으니 민병단이 아닌 분들은 모두 대피하여 주십시오.</color>","JPN":"<color=#ffd34c>第3種侵食体、通称キキーモラが出現。民兵団以外の人は速やかに避難してください。</color>","ENG":"<color=#ffd34c>Category 3 C.O., A.K.A Kikimora has appeared. Everyone except the militia should evacuate the premises.</color>","TWN":"<color=#ffd34c>發現3類侵蝕體奇奇莫拉行蹤，請非民兵團成員全部撤離。</color>"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"BROADCAST_HAVEN_NULL_NULL","text":{"KOREA":"<color=#ffd34c>이건 실제 상황입니다.</color>","JPN":"<color=#ffd34c>これは訓練ではありません。</color>","ENG":"<color=#ffd34c>This is not a drill.</color>","TWN":"<color=#ffd34c>這不是演習。</color>"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"BROADCAST_HAVEN_NULL_NULL","text":{"KOREA":"<color=#ffd34c>다시 한번 알려드립니다.</color>","JPN":"<color=#ffd34c>もう一度お知らせします……</color>","ENG":"<color=#ffd34c>I repeat.</color>","TWN":"<color=#ffd34c>重複，這不是演習。</color>"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"BROADCAST_HAVEN_NULL_NULL","text":{"KOREA":"<color=#ffd34c>3종 침식체, 통칭 키키모라가 출몰했으며……</color>","JPN":"<color=#ffd34c>第3種侵食体、通称キキーモラが出現……</color>","ENG":"<color=#ffd34c>Category 3 C.O., A.K.A Kikimora has appeared...</color>","TWN":"<color=#ffd34c>發現3類侵蝕體奇奇莫拉行蹤……</color>"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"3, 3종이라니?! 말도 안 돼!","JPN":"だ、第3種！？　そんな！","ENG":"A-a Category 3?! That can't be!","TWN":"3，3類？！不可能！"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"사샤! 어디 가는 거야?!","JPN":"サシャ！　どこに行くの！？","ENG":"Sasha! Where are you going?!","TWN":"莎夏！你去哪裡？！"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"당연히 싸우러 가야지!","JPN":"決まってるでしょう！　戦わないと！","ENG":"To fight, of course!","TWN":"當然是去戰鬥！"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"3종은 만만한 개체가 아냐!","JPN":"第3種はそんな簡単に倒せる個体じゃない！","ENG":"But a Category 3 isn't something you can easily defeat on your own!","TWN":"3類可不是好對付的！"},"stage":{"bg":"DORMITORY_3","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L19_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"누가 혼자 싸운대?","JPN":"何も一人で戦うつもりはないよ！","ENG":"Who said anything about fighting alone?","TWN":"誰說要單獨戰鬥了？"},"stage":{"bg":"DORMITORY_3","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L20_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"전선에서 싸우는 건 무리겠지만… 분명 내가 할 수 있는 게 있을 거야.","JPN":"前線で戦うのは無理かもしれないけど……きっと私にできることがあるはず。","ENG":"I might not be fighting it in the forefront, but... I'm sure there's something I can do.","TWN":"雖然在前線戰鬥有些勉強……但我肯定能做點什麼。"},"stage":{"bg":"DORMITORY_3","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L22_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"빨리… 고물들을 잔뜩 들고 가야 해!","JPN":"早く……古鉄をできるだけ運ばないと！","ENG":"C'mon...! We need to bring all the junk we can!","TWN":"快點……得帶上大量的破銅爛鐵！"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"총기, 총알… 보급할 수 있는 건 뭐든 전부 만들어봐야겠어!","JPN":"銃、弾丸……役に立ちそうなものならとにかく何でも作る！","ENG":"Firearms, bullets... I'll make anything that can be helpful.","TWN":"槍支、子彈……能補給的全都得做出來！"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"OLGA_DOLL_NPC_NULL","text":{"KOREA":"이젠 아예 키키모라까지 나타났다고?","JPN":"ついにキキーモラが現れたの？","ENG":"A Kikimora is appearing now?","TWN":"連奇奇莫拉都出現了嗎？"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":null,"C":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"OLGA_DOLL_NPC_NULL","text":{"KOREA":"우리가 살던 곳을 쑥대밭으로 만든 녀석이 분명해.","JPN":"私たちの故郷をめちゃくちゃにしたやつに違いない。","ENG":"It's the same one that devastated our home.","TWN":"一定是毀了我們家園的那隻。"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":null,"C":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"ANDRE_DOLL_NPC_NULL","text":{"KOREA":"확실하군. 그 녀석이 맞아.","JPN":"ああ、間違いない。","ENG":"I'm sure of it. It's that bastard.","TWN":"確定了，就是那個傢伙。"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":{"char_id":"ANDRE_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"MILITIA_DOLL_NPC_NULL","text":{"KOREA":"그 자식만큼은 똑똑히 기억하고 있지!","JPN":"やつのことは昨日のことのように覚えてるぜ！","ENG":"I never forgot how that thing looked!","TWN":"那個傢伙我可是記得清清楚楚！"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"MILITIA_DOLL_NPC_NULL","text":{"KOREA":"하! 결국 끝장을 보겠다고 나타난 건가?","JPN":"はっ！　一人も残さないってことか？","ENG":"Ha! Has it finally shown up to finish what it started?","TWN":"哈！最終還是不肯放過我們嗎？"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"MILITIA_DOLL_NPC_NULL","text":{"KOREA":"이거 이거, 대학살극이 펼쳐지겠구만!","JPN":"これはこれは、大量虐殺の始まりだな！","ENG":"I think... a massacre is about to go down here!","TWN":"這下好了，一場大屠殺要開始了！"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":null,"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":"ANDRE_DOLL_NPC_NULL","text":{"KOREA":"아니, 그렇지 않아!","JPN":"いや、違う！","ENG":"No, that won't happen!","TWN":"不，不會的！"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":null,"C":{"char_id":"ANDRE_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"ANDRE_DOLL_NPC_NULL","text":{"KOREA":"녀석이 우리에게 죽으려고 직접 찾아와준 거다!","JPN":"やつが自ら殺されるためにやってきたんだ！","ENG":"It came back to die to us!","TWN":"那傢伙是來自投羅網的！"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":null,"C":{"char_id":"ANDRE_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"ANDRE_DOLL_NPC_NULL","text":{"KOREA":"고생해서 찾을 수고를 덜었어. 오늘로 확실히 죽이겠다!","JPN":"おかげで捜す手間が省けたな。今日は確実に殺すぞ！","ENG":"It saved us the trouble of tracking it down. Today, we kill it for good!","TWN":"得來全不費工夫，今天一定要徹底幹掉它！"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":null,"C":{"char_id":"ANDRE_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};